class Solution:
    def minZeroArray(self, nums, queries):
        n = len(nums)
        m = len(queries)
        def feasible(k):
            for i in range(n):
                target = nums[i]
                if target == 0:
                    continue
                dp = [False] * (target + 1)
                dp[0] = True
                for j in range(k):
                    l, r, val = queries[j]
                    if l <= i <= r and val <= target:
                        for s in range(target, val - 1, -1):
                            if dp[s - val]:
                                dp[s] = True
                if not dp[target]:
                    return False
            return True
        if not feasible(m):
            return -1
        for k in range(0, m + 1):
            if feasible(k):
                return k
        return -1

