class Solution:
    def minZeroArray(self, nums, queries):
        n = len(nums)
        m = len(queries)
        def feasible(k):
            for i in range(n):
                target = nums[i]
                if target == 0:
                    continue
                reach = 1
                mask = (1 << (target + 1)) - 1
                for j in range(k):
                    l, r, val = queries[j]
                    if l <= i <= r:
                        reach |= (reach << val)
                        reach &= mask
                if not (reach >> target) & 1:
                    return False
            return True
        if not feasible(m):
            return -1
        lo, hi = 0, m
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

