var minZeroArray = function(nums, queries) {
    const n = nums.length;
    const m = queries.length;
    function feasible(k) {
        for (let i = 0; i < n; i++) {
            const target = nums[i];
            if (target === 0) continue;
            let reach = 1n;
            const mask = (1n << BigInt(target + 1)) - 1n;
            for (let j = 0; j < k; j++) {
                const l = queries[j][0], r = queries[j][1], val = queries[j][2];
                if (l <= i && i <= r) {
                    reach |= (reach << BigInt(val));
                    reach &= mask;
                }
            }
            if (((reach >> BigInt(target)) & 1n) === 0n) return false;
        }
        return true;
    }
    if (!feasible(m)) return -1;
    let lo = 0, hi = m;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
